import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useWishlist } from '../context/WishlistContext';

const Header = ({ cartCount, searchQuery, setSearchQuery, clearFilters }) => {
    const { wishlist } = useWishlist();
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [showNotifications, setShowNotifications] = useState(false);
    const [notifications, setNotifications] = useState([]);

    useEffect(() => {
        // Disabled Firebase listener
        setNotifications([]);
    }, []);

    const markAllRead = async () => {
        // Disabled Firebase status update
    };

    const unreadCount = notifications.filter(n => !n.read).length;

    const navigate = useNavigate();


    return (
        <header className="glass" style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            zIndex: 1000,
            padding: '1rem 0'
        }}>
            <div className="container" style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between'
            }}>
                {/* Logo */}
                <Link to="/" onClick={clearFilters} style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <img src="/logo.png" alt="Logo" style={{ width: '40px', height: '40px', objectFit: 'contain' }} />
                    <span style={{ fontSize: '1.5rem', fontWeight: 'bold', letterSpacing: '-1px', color: '#fff' }}>
                        Folder<span style={{ color: 'var(--neon-blue)' }}>Mart</span>
                    </span>
                </Link>

                {/* Search Bar */}
                <div style={{
                    flex: 1,
                    maxWidth: '500px',
                    margin: '0 2rem',
                    position: 'relative'
                }}>
                    <input
                        id="search"
                        name="search"
                        type="text"
                        placeholder="Search for sensors, tools, parts..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        style={{
                            width: '100%',
                            height: '100%', // Ensure it fills container
                            background: 'rgba(255,255,255,0.05)',
                            border: '1px solid var(--glass-border)',
                            borderRadius: '50px',
                            padding: '12px 24px',
                            color: 'var(--text-primary)',
                            outline: 'none',
                            transition: '0.3s'
                        }}
                        onFocus={(e) => e.target.style.borderColor = 'var(--neon-blue)'}
                        onBlur={(e) => e.target.style.borderColor = 'var(--glass-border)'}
                    />
                    <button style={{
                        position: 'absolute',
                        right: '10px',
                        top: '50%',
                        transform: 'translateY(-50%)',
                        background: 'none',
                        border: 'none',
                        color: 'var(--text-secondary)',
                        cursor: 'pointer'
                    }}>
                        ≡ƒöì
                    </button>
                </div>

                {/* Actions */}
                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                    {/* Admin Link - Enhanced Visibility */}
                    {(() => {
                        try {
                            const user = JSON.parse(localStorage.getItem('user'));
                            if (user && user.role === 'admin') {
                                return (
                                    <Link to="/admin" style={{
                                        textDecoration: 'none',
                                        color: '#fff',
                                        background: 'linear-gradient(135deg, #a855f7, #06b6d4)', // Matched to User Image
                                        padding: '12px 28px',
                                        borderRadius: '50px',
                                        fontSize: '0.95rem',
                                        fontWeight: '800',
                                        boxShadow: '0 0 20px rgba(6, 182, 212, 0.4)',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '10px',
                                        transition: '0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                        border: '1px solid rgba(255, 255, 255, 0.2)'
                                    }}
                                        onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.05)'; e.currentTarget.style.boxShadow = '0 0 30px rgba(168, 85, 247, 0.6)'; }}
                                        onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = '0 0 20px rgba(6, 182, 212, 0.4)'; }}>
                                        <span style={{ fontSize: '1.2rem' }}>≡ƒ¢á∩╕Å</span> Manage Store
                                    </Link>
                                );
                            }
                        } catch (e) {
                            return null;
                        }
                    })()}

                    <Link to="/track-order" className="btn-icon" title="Track Order" style={{ transition: '0.3s', borderRadius: '50%' }} onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.boxShadow = '0 0 15px rgba(0, 243, 255, 0.4)'; }} onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = 'none'; }}>
                        ≡ƒôª
                    </Link>

                    <Link to="/profile" className="btn-icon" title="Account" style={{ transition: '0.3s', borderRadius: '50%' }} onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.boxShadow = '0 0 15px rgba(0, 243, 255, 0.4)'; }} onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = 'none'; }}>
                        ≡ƒæñ
                    </Link>

                    {/* Notification Bell */}
                    <div style={{ position: 'relative' }}>
                        <button
                            className="btn-icon"
                            onClick={() => setShowNotifications(!showNotifications)}
                            title="Notifications"
                        >
                            ≡ƒöö
                        </button>
                        {unreadCount > 0 && (
                            <span style={{
                                position: 'absolute', top: '-5px', right: '-5px',
                                background: 'var(--neon-purple)', color: '#fff',
                                borderRadius: '50%', width: '18px', height: '18px',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                fontSize: '0.7rem', fontWeight: 'bold'
                            }}>
                                {unreadCount}
                            </span>
                        )}

                        {/* Notifications Dropdown */}
                        {showNotifications && (
                            <div className="glass" style={{
                                position: 'absolute', top: '45px', right: '0',
                                width: '280px', borderRadius: '12px', zIndex: 1001,
                                padding: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.5)',
                                border: '1px solid var(--glass-border)',
                                animation: 'view-fade 0.3s ease-out'
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px', borderBottom: '1px solid rgba(255,255,255,0.05)', paddingBottom: '8px' }}>
                                    <h4 style={{ margin: '0', fontSize: '0.9rem', color: 'var(--neon-blue)' }}>
                                        Recent Updates
                                    </h4>
                                    {unreadCount > 0 && (
                                        <button
                                            onClick={markAllRead}
                                            style={{ background: 'none', border: 'none', color: 'var(--text-secondary)', fontSize: '0.7rem', cursor: 'pointer', textDecoration: 'underline' }}
                                        >
                                            Mark all read
                                        </button>
                                    )}
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                    {notifications.length > 0 ? notifications.map(n => (
                                        <div key={n.id} style={{
                                            padding: '8px', background: n.read ? 'transparent' : 'rgba(0,243,255,0.03)',
                                            borderRadius: '8px', fontSize: '0.8rem', cursor: 'pointer',
                                            transition: '0.2s'
                                        }} onMouseEnter={(e) => e.target.style.background = 'rgba(255,255,255,0.05)'}>
                                            <p style={{ margin: '0', color: '#fff', lineHeight: '1.4' }}>{n.text}</p>
                                            <span style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }}>{n.time}</span>
                                        </div>
                                    )) : <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', textAlign: 'center' }}>No new messages</p>}
                                </div>
                            </div>
                        )}
                    </div>

                    <div style={{ position: 'relative' }}>
                        <Link to="/wishlist" className="btn-icon" title="Wishlist" style={{ transition: '0.3s', borderRadius: '50%', display: 'flex' }} onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.boxShadow = '0 0 15px rgba(255, 68, 68, 0.4)'; }} onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = 'none'; }}>
                            Γ¥ñ∩╕Å
                        </Link>
                        {wishlist.length > 0 && (
                            <span style={{
                                position: 'absolute',
                                top: '-5px',
                                right: '-5px',
                                background: '#ff4444',
                                color: '#fff',
                                fontSize: '0.7rem',
                                width: '18px',
                                height: '18px',
                                borderRadius: '50%',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontWeight: 'bold'
                            }}>{wishlist.length}</span>
                        )}
                    </div>

                    <div style={{ position: 'relative' }}>
                        <Link to="/cart" className="btn-icon" title="Cart" style={{ transition: '0.3s', borderRadius: '50%', display: 'flex' }} onMouseOver={(e) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.boxShadow = '0 0 15px var(--neon-purple)'; }} onMouseOut={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = 'none'; }}>
                            ≡ƒ¢Æ
                        </Link>
                        {cartCount > 0 && (
                            <span style={{
                                position: 'absolute',
                                top: '-5px',
                                right: '-5px',
                                background: 'var(--neon-purple)',
                                color: '#fff',
                                fontSize: '0.7rem',
                                width: '18px',
                                height: '18px',
                                borderRadius: '50%',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontWeight: 'bold',
                                pointerEvents: 'none'
                            }}>{cartCount}</span>
                        )}
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;

import React from 'react';
import { Link } from 'react-router-dom';
import { useWishlist } from '../context/WishlistContext';
import { useCurrency } from '../context/CurrencyContext';
import API_URL from '../config/api';

const ProductCard = ({ product, onAddToCart }) => {
    const { formatPrice } = useCurrency();
    const { toggleWishlist, isInWishlist } = useWishlist();
    const isSaved = isInWishlist(product.id || product._id);


    // Helper to get an icon based on category
    const getIcon = (cat) => {
        if (cat.includes('Phone')) return '≡ƒô▒';
        if (cat.includes('Audio')) return '≡ƒÄº';
        if (cat.includes('Battery')) return '≡ƒöï';
        if (cat.includes('Display')) return '≡ƒûÑ∩╕Å';
        if (cat.includes('Charger')) return '≡ƒöî';
        if (cat === 'Microcontrollers') return '≡ƒñû';
        return 'ΓÜí';
    };

    return (
        <div className="product-card glass" style={{
            transition: '0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
            border: '1px solid rgba(255,255,255,0.05)'
        }} onMouseOver={e => {
            e.currentTarget.style.transform = 'translateY(-10px)';
            e.currentTarget.style.boxShadow = `0 20px 40px rgba(0, 243, 255, 0.15)`;
            e.currentTarget.style.borderColor = 'rgba(0, 243, 255, 0.3)';
        }} onMouseOut={e => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = 'none';
            e.currentTarget.style.borderColor = 'rgba(255,255,255,0.05)';
        }}>
            {/* Image Container - Clickable */}
            <Link to={`/product/${product.id || product._id}`} className="product-image-container" style={{ textDecoration: 'none', display: 'block' }}>

                {product.image ? (
                    <img
                        src={product.image.startsWith('http') ? product.image : (product.image.startsWith('/') ? `https://folder-mart.onrender.com${product.image}` : product.image)}
                        alt={product.name}
                        className="product-image-placeholder" // Keep class for hover scaling
                        onError={(e) => {
                            e.target.onerror = null;
                            e.target.src = 'https://via.placeholder.com/300x300?text=Product+Image';
                        }}
                        style={{
                            width: '100%',
                            height: '100%',
                            objectFit: 'cover'
                        }}
                    />
                ) : (
                    <div
                        className="product-image-placeholder"
                        style={{
                            width: '100%',
                            height: '100%',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: '#444',
                            fontSize: '3.5rem',
                            background: 'linear-gradient(45deg, #111, #222)'
                        }}
                    >
                        {getIcon(product.category)}
                    </div>
                )}

                <div style={{
                    position: 'absolute',
                    top: '10px',
                    right: '10px',
                    zIndex: 2
                }}>
                    <span className="category-tag">{product.category}</span>
                </div>

                {/* Wishlist Heart */}
                <button
                    onClick={(e) => { e.preventDefault(); e.stopPropagation(); toggleWishlist(product); }}
                    style={{
                        position: 'absolute',
                        top: '45px',
                        right: '10px',
                        zIndex: 3,
                        background: 'rgba(0,0,0,0.3)',
                        border: '1px solid rgba(255,255,255,0.1)',
                        borderRadius: '50%',
                        width: '32px',
                        height: '32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        cursor: 'pointer',
                        color: isSaved ? '#ff4444' : '#fff',
                        transition: '0.3s',
                        backdropFilter: 'blur(5px)'
                    }}
                    title={isSaved ? "Remove from Wishlist" : "Add to Wishlist"}
                >
                    {isSaved ? 'Γ¥ñ∩╕Å' : '≡ƒñì'}
                </button>

                {/* Badges Stack */}
                <div style={{ position: 'absolute', top: '10px', left: '10px', display: 'flex', flexDirection: 'column', gap: '5px', zIndex: 2 }}>
                    {/* Bestseller Badge */}
                    {(product.id?.length % 5 === 0) && (
                        <div style={{
                            background: '#fbbf24', color: '#000', padding: '3px 10px',
                            borderRadius: '4px', fontSize: '0.65rem', fontWeight: 'bold',
                            boxShadow: '0 4px 10px rgba(251, 191, 36, 0.4)'
                        }}>
                            ≡ƒÅå BESTSELLER
                        </div>
                    )}

                    {/* New Badge */}
                    {(product.id?.slice(-1) % 3 === 0) && (
                        <div style={{
                            background: 'var(--neon-purple)', color: '#fff', padding: '3px 10px',
                            borderRadius: '4px', fontSize: '0.65rem', fontWeight: 'bold',
                            boxShadow: '0 4px 10px rgba(112, 0, 255, 0.4)'
                        }}>
                            NEW ARRIVAL
                        </div>
                    )}

                    {/* Low Stock Badge */}
                    {product.stock > 0 && product.stock <= 5 && (
                        <div style={{
                            background: '#ff4444', color: '#fff', padding: '3px 10px',
                            borderRadius: '4px', fontSize: '0.65rem', fontWeight: 'bold',
                            boxShadow: '0 4px 10px rgba(255, 68, 68, 0.4)', animation: 'pulse 2s infinite'
                        }}>
                            ΓÅ│ LIMITED: {product.stock} LEFT
                        </div>
                    )}
                </div>
            </Link>

            {/* Content */}
            <div style={{ padding: '1.5rem', flex: 1, display: 'flex', flexDirection: 'column' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '0.5rem' }}>
                    <Link to={`/product/${product.id || product._id}`} style={{ textDecoration: 'none' }}>
                        <h3 style={{ fontSize: '1.1rem', color: '#fff', lineHeight: '1.3' }} className="hover-cyan">{product.name}</h3>
                    </Link>
                    <span style={{ fontSize: '0.9rem', color: '#fbbf24' }}>Γÿà 4.8</span>
                </div>

                <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', marginBottom: '1.5rem', flex: 1, lineHeight: '1.5' }}>
                    {product.description}
                </p>

                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 'auto' }}>
                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                        {product.original_price && product.original_price > product.price && (
                            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', textDecoration: 'line-through' }}>
                                    {formatPrice(product.original_price)}
                                </span>
                                <span style={{ fontSize: '0.7rem', color: '#10b981', fontWeight: 'bold' }}>
                                    -{Math.round(((product.original_price - product.price) / product.original_price) * 100)}%
                                </span>
                            </div>
                        )}
                        <span style={{ fontSize: '1.4rem', fontWeight: 'bold', color: 'var(--neon-blue)' }}>
                            {formatPrice(product.price)}
                        </span>
                    </div>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                        {(() => {
                            try {
                                const user = JSON.parse(localStorage.getItem('user'));
                                if (user && user.role === 'admin') {
                                    return (
                                        <Link
                                            to={`/admin/edit/${product.id || product._id}`}
                                            className="btn-primary"
                                            style={{
                                                padding: '10px 14px',
                                                fontSize: '0.9rem',
                                                borderRadius: '50px',
                                                background: 'transparent',
                                                border: '1px solid var(--neon-purple)',
                                                color: 'var(--neon-purple)',
                                                textDecoration: 'none',
                                                display: 'flex',
                                                alignItems: 'center'
                                            }}
                                            title="Edit Product"
                                        >
                                            Γ£Å∩╕Å
                                        </Link>
                                    );
                                }
                            } catch (e) { return null; }
                        })()}
                        <button
                            className="btn-primary"
                            style={{
                                padding: '10px 20px',
                                fontSize: '0.9rem',
                                borderRadius: '50px',
                                transition: '0.3s'
                            }}
                            onMouseOver={e => e.currentTarget.style.transform = 'scale(1.05)'}
                            onMouseOut={e => e.currentTarget.style.transform = 'scale(1)'}
                            onClick={() => onAddToCart(product)}
                        >
                            Add +
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ProductCard;

import React, { createContext, useState, useEffect, useContext } from 'react';

const CurrencyContext = createContext();

export const useCurrency = () => useContext(CurrencyContext);

export const CurrencyProvider = ({ children }) => {
    const [currency, setCurrency] = useState(localStorage.getItem('preferred_currency') || 'INR');
    const [rate, setRate] = useState(1);
    const [loading, setLoading] = useState(true);

    const currencies = {
        'INR': { symbol: 'Γé╣', rate: 1 },
        'USD': { symbol: '$', rate: 0.012 },
        'EUR': { symbol: 'Γé¼', rate: 0.011 },
        'GBP': { symbol: '┬ú', rate: 0.0095 },
    };

    useEffect(() => {
        const initCurrency = async () => {
            const savedCurrency = localStorage.getItem('preferred_currency');
            if (savedCurrency) {
                updateRate(savedCurrency);
                setLoading(false);
                return;
            }

            try {
                // Auto-detect if no preference
                const ipRes = await fetch('https://ipapi.co/json/');
                const ipData = await ipRes.json();
                const detectedCurrency = ipData.currency || 'INR';

                if (currencies[detectedCurrency]) {
                    setCurrency(detectedCurrency);
                    updateRate(detectedCurrency);
                } else {
                    setCurrency('INR');
                    setRate(1);
                }
            } catch (error) {
                setCurrency('INR');
                setRate(1);
            } finally {
                setLoading(false);
            }
        };

        initCurrency();
    }, []);

    const updateRate = async (cur) => {
        if (cur === 'INR') {
            setRate(1);
            return;
        }
        try {
            const res = await fetch(`https://api.exchangerate-api.com/v4/latest/INR`);
            const data = await res.json();
            setRate(data.rates[cur] || currencies[cur].rate);
        } catch (e) {
            setRate(currencies[cur].rate); // Fallback to static rates
        }
    };

    const changeCurrency = (newCur) => {
        setCurrency(newCur);
        localStorage.setItem('preferred_currency', newCur);
        updateRate(newCur);
    };

    const formatPrice = (priceInINR) => {
        if (loading) return '...';
        const converted = priceInINR * rate;

        return new Intl.NumberFormat(undefined, {
            style: 'currency',
            currency: currency
        }).format(converted);
    };

    const value = {
        currency,
        rate,
        formatPrice,
        changeCurrency,
        loading,
        availableCurrencies: Object.keys(currencies)
    };

    return (
        <CurrencyContext.Provider value={value}>
            {children}
        </CurrencyContext.Provider>
    );
};

import React, { useState, useEffect, createContext, useContext } from 'react';

const ToastContext = createContext();

export const ToastProvider = ({ children }) => {
    const [toasts, setToasts] = useState([]);

    const showToast = (message, type = 'success') => {
        const id = Math.random().toString(36).substr(2, 9);
        setToasts((prev) => [...prev, { id, message, type }]);
        setTimeout(() => {
            setToasts((prev) => prev.filter((t) => t.id !== id));
        }, 3000);
    };

    return (
        <ToastContext.Provider value={{ showToast }}>
            {children}
            <div style={{
                position: 'fixed',
                bottom: '2rem',
                right: '2rem',
                zIndex: 9999,
                display: 'flex',
                flexDirection: 'column',
                gap: '0.8rem'
            }}>
                {toasts.map((toast) => (
                    <div
                        key={toast.id}
                        style={{
                            background: toast.type === 'error' ? 'rgba(255, 68, 68, 0.9)' : 'rgba(0, 243, 255, 0.9)',
                            color: toast.type === 'error' ? '#fff' : '#000',
                            padding: '12px 24px',
                            borderRadius: '12px',
                            backdropFilter: 'blur(10px)',
                            boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3)',
                            fontWeight: '600',
                            fontSize: '0.9rem',
