import React, { createContext, useContext, useState, useEffect } from 'react';
import { useToast } from './ToastContext';

const WishlistContext = createContext();

export const WishlistProvider = ({ children }) => {
    const [wishlist, setWishlist] = useState([]);
    const { showToast } = useToast();

    // Load from localStorage on init
    useEffect(() => {
        const saved = localStorage.getItem('wishlist');
        if (saved) {
            try {
                setWishlist(JSON.parse(saved));
            } catch (e) {
                setWishlist([]);
            }
        }
    }, []);

    // Save to localStorage whenever it changes
    useEffect(() => {
        localStorage.setItem('wishlist', JSON.stringify(wishlist));
    }, [wishlist]);

    const toggleWishlist = (product) => {
        const isWishlisted = wishlist.some(item => (item.id || item._id) === (product.id || product._id));

        if (isWishlisted) {
            setWishlist(prev => prev.filter(item => (item.id || item._id) !== (product.id || product._id)));
            showToast(`${product.name} removed from wishlist.`, 'success');
        } else {
            setWishlist(prev => [...prev, product]);
            showToast(`${product.name} saved to wishlist! Γ¥ñ∩╕Å`);
        }
    };

    const isInWishlist = (productId) => {
        return wishlist.some(item => (item.id || item._id) === productId);
    };

    return (
        <WishlistContext.Provider value={{ wishlist, toggleWishlist, isInWishlist }}>
            {children}
        </WishlistContext.Provider>
    );
};

export const useWishlist = () => useContext(WishlistContext);

import React, { useState, useEffect } from 'react';
import { API_URL } from '../../config/api';
import { useToast } from '../../context/ToastContext';
import { useCurrency } from '../../context/CurrencyContext';

const OrderManagement = () => {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const { showToast } = useToast();
    const { formatPrice } = useCurrency();

    const fetchOrders = async () => {
        setLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/payment/orders`); // Need to ensure this route exists or update logic
            // Fallback: Using Firestore directly on client if route not ready, but better to use API
            // For now, let's assume API is preferred
            if (!res.ok) throw new Error('Failed to fetch');
            const data = await res.json();
            setOrders(data || []);
        } catch (error) {
            console.error('Error fetching orders:', error);
            showToast('Failed to fetch orders.', 'error');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();
    }, []);

    const handleStatusChange = async (orderId, newStatus) => {
        try {
            const res = await fetch(`${API_URL}/api/payment/orders/${orderId}/status`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus })
            });

            if (!res.ok) throw new Error('Update failed');

            setOrders(orders.map(order =>
                order.id === orderId ? { ...order, status: newStatus } : order
            ));

            showToast(`Order status updated to ${newStatus} Γ£¿`);
        } catch (error) {
            console.error('Error updating status:', error);
            showToast('Failed to update status.', 'error');
        }
    };

    if (loading) return <div className="container" style={{ paddingTop: '120px', textAlign: 'center' }}>Loading Orders...</div>;

    return (
        <div className="container" style={{ paddingTop: '100px', minHeight: '80vh' }}>
            <h2 style={{ marginBottom: '2rem', borderLeft: '4px solid var(--neon-blue)', paddingLeft: '1rem' }}>Order Management</h2>

            <div className="glass" style={{ padding: '2rem', borderRadius: '16px', overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', color: 'var(--text-secondary)', minWidth: '800px' }}>
                    <thead>
                        <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', textAlign: 'left' }}>
                            <th style={{ padding: '1rem', color: '#fff' }}>Order ID</th>
                            <th style={{ padding: '1rem', color: '#fff' }}>Customer / Email</th>
                            <th style={{ padding: '1rem', color: '#fff' }}>Status</th>
                            <th style={{ padding: '1rem', color: '#fff' }}>Total</th>
                            <th style={{ padding: '1rem', color: '#fff' }}>Items</th>
                            <th style={{ padding: '1rem', color: '#fff' }}>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {orders.map(order => (
                            <tr key={order.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)', transition: '0.2s', background: 'transparent' }} onMouseOver={e => e.currentTarget.style.background = 'rgba(255,255,255,0.01)'} onMouseOut={e => e.currentTarget.style.background = 'transparent'}>
                                <td style={{ padding: '1rem', color: 'var(--neon-blue)', fontFamily: 'monospace' }}>
                                    {order.id.substring(0, 8)}...
                                </td>
                                <td style={{ padding: '1rem' }}>
                                    <div style={{ color: '#fff', fontWeight: 'bold' }}>{order.email}</div>
                                    <div style={{ fontSize: '0.8rem', opacity: 0.7 }}>{order.paymentMethod}</div>
                                </td>
                                <td style={{ padding: '1rem' }}>
                                    <span style={{
                                        padding: '4px 12px',
                                        borderRadius: '50px',
                                        fontSize: '0.75rem',
                                        fontWeight: '700',
                                        letterSpacing: '0.5px',
                                        background: order.status === 'Delivered' ? 'rgba(74, 222, 128, 0.1)' : (order.status === 'Cancelled' ? 'rgba(239, 68, 68, 0.1)' : 'rgba(0, 243, 255, 0.1)'),
                                        color: order.status === 'Delivered' ? '#4ade80' : (order.status === 'Cancelled' ? '#ef4444' : 'var(--neon-blue)'),
                                        border: `1px solid ${order.status === 'Delivered' ? 'rgba(74, 222, 128, 0.3)' : (order.status === 'Cancelled' ? 'rgba(239, 68, 68, 0.3)' : 'rgba(0, 243, 255, 0.3)')}`,
                                        textTransform: 'uppercase'
                                    }}>
                                        {order.status}
                                    </span>
                                </td>
                                <td style={{ padding: '1rem', color: '#fff', fontWeight: 'bold' }}>
                                    {formatPrice(order.totalAmount)}
                                </td>
                                <td style={{ padding: '1rem', fontSize: '0.85rem' }}>
                                    {order.items.length} items
                                </td>
                                <td style={{ padding: '1rem' }}>
                                    <select
                                        value={order.status}
                                        onChange={(e) => handleStatusChange(order.id, e.target.value)}
                                        style={{
                                            background: 'rgba(0,0,0,0.3)',
                                            color: '#fff',
                                            border: '1px solid var(--glass-border)',
                                            padding: '5px',
                                            borderRadius: '4px',
                                            outline: 'none'
                                        }}
                                    >
                                        <option value="Processing">Processing</option>
                                        <option value="Shipped">Shipped</option>
                                        <option value="Delivered">Delivered</option>
                                        <option value="Cancelled">Cancelled</option>
                                    </select>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {orders.length === 0 && (
                    <div style={{ textAlign: 'center', padding: '3rem' }}>No orders found.</div>
                )}
            </div>
        </div>
    );
};

export default OrderManagement;

