const Home = ({ addToCart, searchQuery, setSearchQuery }) => {
    const [searchParams] = useSearchParams();
    const categoryParam = searchParams.get('category');

    const [activeCategory, setActiveCategory] = useState(categoryParam || 'All');
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [email, setEmail] = useState('');
    const [submitting, setSubmitting] = useState(false);
    const [timeLeft, setTimeLeft] = useState({ hours: 12, minutes: 0, seconds: 0 });
    const [sortBy, setSortBy] = useState('newest'); // 'price-low', 'price-high', 'newest', 'rating'
    const [priceRange, setPriceRange] = useState({ min: 0, max: 200000 });

    const { showToast } = useToast();
    const { formatPrice } = useCurrency();
    const productSectionRef = useRef(null);

    // Flash Sale Timer (Persistent)
    useEffect(() => {
        // Set fixed end time (e.g., end of current day or next 24h)
        const targetDate = new Date();
        targetDate.setHours(23, 59, 59, 999); // End of today

        const calculateTimeLeft = () => {
            const now = new Date();
            const difference = targetDate - now;

            if (difference > 0) {
                return {
                    hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
                    minutes: Math.floor((difference / 1000 / 60) % 60),
                    seconds: Math.floor((difference / 1000) % 60)
                };
            }
            return { hours: 0, minutes: 0, seconds: 0 };
        };

        const timer = setInterval(() => {
            setTimeLeft(calculateTimeLeft());
        }, 1000);
        return () => clearInterval(timer);
    }, []);

    const handleSubscribe = async (e) => {
        e.preventDefault();
        if (!email) return;
        setSubmitting(true);
        try {
            const res = await fetch(`${API_URL}/api/marketing/subscribe`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email, type: 'general' })
            });
            if (res.ok) {
                showToast('Welcome to the inner circle! ≡ƒÆî', 'success');
                setEmail('');
            } else {
                throw new Error('Failed to subscribe');
            }
        } catch (err) {
            showToast('Unable to subscribe. Please try again later.', 'error');
        } finally {
            setSubmitting(false);
        }
    };

    // Update activeCategory when URL param changes
    useEffect(() => {
        if (categoryParam) {
            setActiveCategory(categoryParam);
            if (productSectionRef.current) {
                productSectionRef.current.scrollIntoView({ behavior: 'smooth' });
            }
        }
    }, [categoryParam]);

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const res = await fetch(`${API_URL}/api/products`);
                if (!res.ok) throw new Error('Failed to fetch products');
                const data = await res.json();
                setProducts(Array.isArray(data) ? data : []);
            } catch (error) {
                console.error('Error fetching products from API:', error);
                setProducts([]);
            } finally {
                setLoading(false);
            }
        };

        fetchProducts();
    }, []);

    const scrollToProducts = () => {
        productSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    let filteredProducts = products.filter(p => {
        const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
        const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            p.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
            p.category.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesPrice = p.price >= priceRange.min && p.price <= priceRange.max;
        return matchesCategory && matchesSearch && matchesPrice;
    });

    // Apply Sorting
    filteredProducts = [...filteredProducts].sort((a, b) => {
        if (sortBy === 'price-low') return a.price - b.price;
        if (sortBy === 'price-high') return b.price - a.price;
        if (sortBy === 'newest') return new Date(b.created_at || 0) - new Date(a.created_at || 0);
        if (sortBy === 'rating') return (b.rating || 0) - (a.rating || 0);
        return 0;
    });


    return (
        <div className="home-container" style={{ paddingBottom: '4rem' }}>
            {/* Flash Sale Banner - Refined Tech Styling */}
            <div className="flash-sale-bar" style={{
                background: 'rgba(255, 68, 68, 0.15)',
                backdropFilter: 'blur(10px)',
                color: '#ff4444',
                padding: '12px 0',
                textAlign: 'center',
                fontWeight: '800',
                fontSize: '0.85rem',
                position: 'sticky',
                top: '70px',
                zIndex: 998,
                borderBottom: '1px solid rgba(255, 68, 68, 0.3)',
                boxShadow: '0 4px 20px rgba(0,0,0,0.5)',
                textTransform: 'uppercase',
                letterSpacing: '1.5px',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                gap: '15px'
            }}>
                <span style={{ animation: 'pulse 2s infinite' }}>ΓÜí MISSION CRITICAL: FLASH SALE ENDS IN</span>
                <span style={{
                    background: 'rgba(255, 68, 68, 0.2)',
                    padding: '2px 10px',
                    borderRadius: '4px',
                    border: '1px solid rgba(255, 68, 68, 0.5)',
                    color: '#fff',
                    fontFamily: 'monospace',
                    fontSize: '1rem'
                }}>
                    {String(timeLeft.hours).padStart(2, '0')}:{String(timeLeft.minutes).padStart(2, '0')}:{String(timeLeft.seconds).padStart(2, '0')}
                </span>
                <span>| UP TO 50% CREDITS RETURN</span>
            </div>

            <div className="hero-section tech-scanner" style={{
                paddingTop: '120px',
                paddingBottom: '4rem',
                textAlign: 'center',
                position: 'relative',
                overflow: 'hidden',
                background: 'radial-gradient(circle at center, #1a1a2e 0%, #0a0a12 100%)'
            }}>
                {/* Simplified Background */}
                <div style={{ position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, background: 'url("https://www.transparenttextures.com/patterns/carbon-fibre.png")', opacity: 0.1 }}></div>

                <div className="container" style={{ position: 'relative', zIndex: 2 }}>
                    <h1 style={{ marginBottom: '0.5rem', fontSize: '3.5rem', letterSpacing: '2px', fontWeight: '800' }}>
                        FUTURE OF <span className="text-gradient" style={{ position: 'relative' }}>
                            TECH
                            <span style={{ position: 'absolute', bottom: '0', left: '0', width: '100%', height: '4px', background: 'var(--neon-blue)', boxShadow: '0 0 15px var(--neon-blue)', borderRadius: '2px' }}></span>
                        </span> SHOPPING
                    </h1>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '1.2rem', maxWidth: '700px', margin: '0 auto 2.5rem' }}>
                        Premium components and hardware for the modern creator. High performance, zero compromise.
                    </p>

                    <div style={{ marginTop: '2.5rem', display: 'flex', gap: '1.5rem', justifyContent: 'center' }}>
                        <button className="btn-primary" onClick={scrollToProducts} style={{ padding: '12px 35px', borderRadius: '50px' }}>SHOP CATALOG</button>
                        <button
                            className="btn-primary"
                            style={{
                                background: 'rgba(0, 243, 255, 0.05)',
                                border: '1px solid rgba(0, 243, 255, 0.3)',
                                color: 'var(--neon-blue)',
                                padding: '12px 35px',
                                borderRadius: '50px',
                                backdropFilter: 'blur(5px)',
                                transition: '0.3s'
                            }}
                            onMouseOver={(e) => { e.currentTarget.style.background = 'rgba(0, 243, 255, 0.15)'; e.currentTarget.style.borderColor = 'var(--neon-blue)'; }}
                            onMouseOut={(e) => { e.currentTarget.style.background = 'rgba(0, 243, 255, 0.05)'; e.currentTarget.style.borderColor = 'rgba(0, 243, 255, 0.3)'; }}
                            onClick={scrollToProducts}
                        >
                            VIEW DEALS
                        </button>
                    </div>
                </div>
            </div>

            <main className="container" style={{ minHeight: '60vh' }}>
                <section ref={productSectionRef}>
                    <div style={{ marginBottom: '2rem' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
                            <h3 style={{ borderLeft: '4px solid var(--neon-blue)', paddingLeft: '1rem' }}>Browse Catalog</h3>
                            <div style={{ display: 'flex', gap: '1rem', alignItems: 'center', flexWrap: 'wrap' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', background: 'rgba(255,255,255,0.05)', padding: '5px 15px', borderRadius: '30px', border: '1px solid var(--glass-border)' }}>
                                    <label htmlFor="price-filter-range" style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', whiteSpace: 'nowrap' }}>Max Price: {formatPrice(priceRange.max)}</label>
                                    <input
                                        id="price-filter-range"
                                        name="price_range_max"
                                        type="range"
                                        min="0"
                                        max="200000"
                                        step="500"
                                        value={priceRange.max}
                                        onChange={(e) => setPriceRange({ ...priceRange, max: parseInt(e.target.value) })}
                                        style={{ accentColor: 'var(--neon-blue)', cursor: 'pointer' }}
                                    />
                                </div>

                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.05)', padding: '5px 15px', borderRadius: '30px', border: '1px solid var(--glass-border)' }}>
                                    <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Sort By:</span>
                                    <select
                                        value={sortBy}
                                        onChange={(e) => setSortBy(e.target.value)}
                                        style={{ background: 'transparent', color: '#fff', border: 'none', outline: 'none', cursor: 'pointer', fontSize: '0.8rem' }}
                                    >
                                        <option value="newest" style={{ background: '#080808' }}>Newest Arrivals</option>
                                        <option value="price-low" style={{ background: '#080808' }}>Price: Low to High</option>
                                        <option value="price-high" style={{ background: '#080808' }}>Price: High to Low</option>
                                        <option value="rating" style={{ background: '#080808' }}>Top Rated</option>
                                    </select>
                                </div>
                            </div>
                        </div>

                        {/* Category Filter Pills */}
                        <div style={{
                            display: 'flex',
                            gap: '1rem',
                            overflowX: 'auto',
                            paddingBottom: '1rem',
                            marginTop: '1.5rem',
                            scrollbarWidth: 'none'
                        }}>
                            {CATEGORIES.map(cat => (
                                <button
                                    key={cat}
                                    onClick={() => setActiveCategory(cat)}
                                    style={{
                                        background: activeCategory === cat ? 'var(--neon-blue)' : 'rgba(255,255,255,0.05)',
                                        color: activeCategory === cat ? '#000' : 'var(--text-secondary)',
                                        border: activeCategory === cat ? '1px solid var(--neon-blue)' : '1px solid var(--glass-border)',
                                        padding: '8px 20px',
                                        borderRadius: '50px',
                                        whiteSpace: 'nowrap',
                                        cursor: 'pointer',
                                        fontWeight: '600',
                                        transition: '0.3s',
                                        boxShadow: activeCategory === cat ? '0 0 15px rgba(0, 243, 255, 0.3)' : 'none'
                                    }}
                                >
                                    {cat}
                                </button>
                            ))}
                        </div>
                    </div>

                    {loading ? (
                        <LoadingSkeleton />
                    ) : (
                        <>
                            <div style={{
                                display: 'grid',
                                gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                                gap: '2rem'
                            }}>
                                {filteredProducts.map((product, index) => (
                                    <ProductCard
                                        key={product.id || product._id || index}
                                        product={product}
                                        onAddToCart={addToCart}
                                    />
                                ))}
                            </div>

                            {filteredProducts.length === 0 && (
                                <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--text-secondary)' }}>
                                    <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>≡ƒöì</div>
                                    <p style={{ marginBottom: '1.5rem' }}>No products found in this category.</p>
                                    <button
                                        className="btn-primary"
                                        onClick={() => {
                                            setActiveCategory('All');
                                            setSearchQuery(''); // Clear internal search query as well
                                            // window.location.href = '/'; // This would refresh the page, better to just update state
                                        }}
                                        style={{ padding: '8px 24px' }}
                                    >
                                        CLEAR ALL FILTERS
                                    </button>
                                </div>
                            )}
                        </>
                    )}
                </section>

            </main>
        </div>
    );
};

export default Home;

import React, { useState, useEffect } from 'react';
import API_URL from '../config/api';
import { useParams, Link, useNavigate } from 'react-router-dom';
import ProductCard from '../components/ProductCard';
import { useCurrency } from '../context/CurrencyContext';
import { useWishlist } from '../context/WishlistContext';
import { useToast } from '../context/ToastContext';
import LoadingSkeleton from '../components/LoadingSkeleton';

const ProductDetails = ({ addToCart }) => {
    const { id } = useParams();
    const { formatPrice } = useCurrency();
    const { toggleWishlist, isInWishlist } = useWishlist();
    const [product, setProduct] = useState(null);
    const [relatedProducts, setRelatedProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [reviews, setReviews] = useState([]);
    const [reviewLoading, setReviewLoading] = useState(false);
    const [alertLoading, setAlertLoading] = useState(false);
    const [newReview, setNewReview] = useState({ rating: 5, comment: '' });
    const { showToast } = useToast();
    const navigate = useNavigate();


    const isSaved = product ? isInWishlist(product.id || product._id) : false;

    useEffect(() => {
        const fetchProductData = async () => {
            setLoading(true);
            try {
                // Fetch main product via API
                const res = await fetch(`${API_URL}/api/products`);
                const allProducts = await res.json();
                const mainProduct = allProducts.find(p => p.id === id);

                if (!mainProduct) throw new Error('Product not found');
                setProduct(mainProduct);

                // Track Recently Viewed
                try {
                    const recent = JSON.parse(localStorage.getItem('recentlyViewed') || '[]');
                    const filtered = recent.filter(p => (p.id || p._id) !== (mainProduct.id || mainProduct._id));
                    const updated = [mainProduct, ...filtered].slice(0, 10);
                    localStorage.setItem('recentlyViewed', JSON.stringify(updated));
                } catch (err) {
                    console.error('Recently Viewed Error:', err);
                }

                // Fetch related products
                const related = allProducts.filter(p => p.category === mainProduct.category && p.id !== id).slice(0, 4);
                setRelatedProducts(related);

            } catch (error) {
                console.error('Error fetching details:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchProductData();
        fetchReviews();
        window.scrollTo(0, 0);
    }, [id]);

    const fetchReviews = async () => {
        try {
            // Using API if available or direct Firestore Client
            const res = await fetch(`${API_URL}/api/marketing/reviews/${id}`); // Assumes we add this
            if (res.ok) {
                const data = await res.json();
                setReviews(data || []);
            }
        } catch (error) {
            console.error('Error fetching reviews:', error);
        }
    };

    const handleReviewSubmit = async (e) => {
        e.preventDefault();
        const user = JSON.parse(localStorage.getItem('user'));
        if (!user) {
            showToast('Please login to submit a review.', 'error');
            return;
        }

        setReviewLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/marketing/reviews`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    product_id: id,
                    user_id: user.id,
                    user_name: `${user.firstName} ${user.lastName}`,
                    rating: newReview.rating,
                    comment: newReview.comment
                })
            });

            if (!res.ok) throw new Error('Failed to submit review');

            showToast('Review submitted! Thank you. Γ£¿');
            setNewReview({ rating: 5, comment: '' });
            fetchReviews();
        } catch (error) {
            console.error('Error submitting review:', error);
            showToast('Failed to submit review.', 'error');
        } finally {
            setReviewLoading(false);
        }
    };

    const handleJoinWaitlist = async (type) => {
        const userStr = localStorage.getItem('user');
        if (!userStr) {
            showToast('Please login to set product alerts.', 'error');
            return;
        }

        const user = JSON.parse(userStr);
        setAlertLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/marketing/waitlist`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    email: user.email,
                    product_id: product.id,
                    alert_type: type
                })
            });
            const data = await res.json();
            if (res.ok) {
                showToast(data.message, 'success');
            } else {
                throw new Error(data.message);
            }
        } catch (error) {
            showToast('Failed to join waitlist.', 'error');
        } finally {
            setAlertLoading(false);
        }
    };

    if (loading) return (
        <div className="container" style={{ paddingTop: '120px' }}>
            <LoadingSkeleton />
        </div>
    );
    if (!product) return <div style={{ color: '#fff', textAlign: 'center', padding: '100px' }}>Product not found.</div>;

    return (
        <div className="container" style={{ paddingTop: '120px', paddingBottom: '4rem' }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '3rem', marginBottom: '4rem' }}>
                {/* Image Section */}
                <div className="glass" style={{ padding: '2rem', borderRadius: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '400px' }}>
                    {product.image ? (
                        <img
                            src={product.image}
                            alt={product.name}
                            style={{ maxWidth: '100%', maxHeight: '500px', objectFit: 'contain', borderRadius: '12px', boxShadow: '0 0 30px rgba(0,243,255,0.2)' }}
                        />
                    ) : (
                        <div style={{ fontSize: '5rem' }}>≡ƒô╖</div>
                    )}
                </div>

                {/* Details Section */}
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <div style={{ marginBottom: '1rem' }}>
                        <span style={{
                            background: 'rgba(0, 243, 255, 0.1)',
                            color: 'var(--neon-blue)',
                            padding: '4px 12px',
                            borderRadius: '50px',
                            fontSize: '0.9rem',
                            fontWeight: '600'
                        }}>
                            {product.category}
                        </span>
                    </div>

                    <h1 style={{ fontSize: '3rem', marginBottom: '1rem', color: '#fff' }}>{product.name}</h1>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '2rem' }}>
                        <span style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'var(--neon-blue)' }}>
                            {formatPrice(product.price)}
                        </span>
                        {product.original_price && product.original_price > product.price && (
                            <>
                                <span style={{ fontSize: '1.2rem', color: 'var(--text-secondary)', textDecoration: 'line-through' }}>
                                    {formatPrice(product.original_price)}
                                </span>
                                <span style={{ background: '#10b981', color: '#fff', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem', fontWeight: 'bold' }}>
                                    SAVE {Math.round(((product.original_price - product.price) / product.original_price) * 100)}%
                                </span>
                            </>
                        )}
                    </div>

                    <div style={{ display: 'flex', gap: '10px', marginBottom: '1.5rem', flexWrap: 'wrap' }}>
                        <button
                            onClick={() => handleJoinWaitlist('price-drop')}
                            disabled={alertLoading}
                            style={{
                                padding: '6px 15px', borderRadius: '50px', background: 'rgba(255,255,255,0.05)',
                                border: '1px solid var(--glass-border)', color: 'var(--text-secondary)',
                                fontSize: '0.8rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px'
                            }}
                        >
                            ≡ƒöö Price Alert
                        </button>
                        {product.stock <= 0 && (
                            <button
                                onClick={() => handleJoinWaitlist('restock')}
                                disabled={alertLoading}
                                style={{
                                    padding: '6px 15px', borderRadius: '50px', background: 'rgba(0,243,255,0.1)',
                                    border: '1px solid var(--neon-blue)', color: 'var(--neon-blue)',
                                    fontSize: '0.8rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px'
                                }}
                            >
                                ≡ƒôª Notify Restock
                            </button>
                        )}
                    </div>

                    <p style={{ color: 'var(--text-primary)', fontSize: '1.1rem', lineHeight: '1.8', marginBottom: '2.5rem', opacity: 0.8 }}>
                        {product.description}
                    </p>

                    <div style={{ display: 'flex', gap: '1rem', marginBottom: '3rem' }}>
                        <button
                            className="btn-primary"
                            onClick={() => addToCart(product)}
                            style={{ padding: '15px 40px', fontSize: '1.1rem', flex: 1, textTransform: 'uppercase' }}
                        >
                            ADD TO CART ≡ƒ¢Æ
                        </button>
                        <button
                            className="btn-primary"
                            onClick={() => {
                                addToCart(product);
                                navigate('/checkout');
                            }}
                            style={{
                                padding: '15px 40px', fontSize: '1.1rem', flex: 1,
                                textTransform: 'uppercase', background: 'var(--neon-purple)',
                                border: '1px solid var(--neon-purple)', boxShadow: '0 0 20px rgba(112, 0, 255, 0.3)'
                            }}
                        >
                            BUY NOW ΓÜí
                        </button>
                        <button
                            onClick={() => toggleWishlist(product)}
                            style={{
                                background: isSaved ? 'rgba(255, 68, 68, 0.1)' : 'rgba(255,255,255,0.05)',
                                border: `1px solid ${isSaved ? '#ff4444' : 'var(--glass-border)'}`,
                                color: isSaved ? '#ff4444' : '#fff',
                                padding: '15px 20px',
                                borderRadius: '12px',
                                cursor: 'pointer',
                                transition: '0.3s',
                                fontSize: '1.2rem'
                            }}
                            title={isSaved ? "Remove from Wishlist" : "Add to Wishlist"}
                        >
                            {isSaved ? 'Γ¥ñ∩╕Å' : '≡ƒñì'}
                        </button>
                    </div>

                    {/* Technical Specifications */}
                    <div style={{ marginTop: '2rem' }}>
                        <h3 style={{ marginBottom: '1.5rem', color: '#fff', fontSize: '1.2rem' }}>Technical Specifications</h3>
                        <div className="glass" style={{ borderRadius: '16px', overflow: 'hidden' }}>
                            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                                <tbody>
                                    <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                        <td style={{ padding: '12px', color: 'var(--text-secondary)', width: '40%' }}>Processor</td>
                                        <td style={{ padding: '12px', color: '#fff' }}>Latest Gen AI Optimized</td>
                                    </tr>
                                    <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                        <td style={{ padding: '12px', color: 'var(--text-secondary)' }}>Model</td>
                                        <td style={{ padding: '12px', color: '#fff' }}>{product.category}-X200</td>
                                    </tr>
                                    <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                        <td style={{ padding: '12px', color: 'var(--text-secondary)' }}>Connectivity</td>
                                        <td style={{ padding: '12px', color: '#fff' }}>Bluetooth 5.3, WiFi 6E</td>
                                    </tr>
                                    <tr>
                                        <td style={{ padding: '12px', color: 'var(--text-secondary)' }}>Status</td>
                                        <td style={{ padding: '12px', color: '#44ff44' }}>Live & Ready</td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>

            {/* Related Products */}
            {relatedProducts.length > 0 && (
                <div style={{ marginTop: '5rem' }}>
                    <h2 style={{ marginBottom: '2rem', borderLeft: '4px solid var(--neon-blue)', paddingLeft: '1rem' }}>You may also like</h2>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '2rem' }}>
                        {relatedProducts.map(rp => (
                            <ProductCard key={rp.id} product={rp} onAddToCart={addToCart} />
                        ))}
                    </div>
                </div>
            )}

            {/* Reviews Section */}
            <div style={{ marginTop: '5rem' }}>
                <h2 style={{ marginBottom: '2rem', borderLeft: '4px solid var(--neon-purple)', paddingLeft: '1rem' }}>Customer Reviews</h2>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '3rem' }}>
                    {/* Submit Review */}
                    <div className="glass" style={{ padding: '2rem', borderRadius: '16px', height: 'fit-content' }}>
                        <h3 style={{ marginBottom: '1.5rem', color: '#fff', fontSize: '1.2rem' }}>Share your feedback</h3>
                        <form onSubmit={handleReviewSubmit}>
                            <div style={{ marginBottom: '1.5rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Rating</label>
                                <div style={{ display: 'flex', gap: '0.5rem', fontSize: '1.5rem' }}>
                                    {[1, 2, 3, 4, 5].map(star => (
                                        <span
                                            key={star}
                                            onClick={() => setNewReview({ ...newReview, rating: star })}
                                            style={{ cursor: 'pointer', color: star <= newReview.rating ? '#fbbf24' : '#444', transition: '0.2s' }}
                                        >
                                            Γÿà
                                        </span>
                                    ))}
                                </div>
                            </div>
                            <div style={{ marginBottom: '1.5rem' }}>
                                <label htmlFor="comment" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Your Review</label>
                                <textarea
                                    id="comment"
                                    value={newReview.comment}
                                    onChange={(e) => setNewReview({ ...newReview, comment: e.target.value })}
                                    required
                                    style={{ width: '100%', background: 'rgba(0,0,0,0.3)', border: '1px solid var(--glass-border)', padding: '12px', borderRadius: '8px', color: '#fff', outline: 'none' }}
                                    rows="4"
                                    placeholder="What did you like or dislike?..."
                                ></textarea>
                            </div>
                            <button className="btn-primary" type="submit" disabled={reviewLoading} style={{ width: '100%' }}>
                                {reviewLoading ? 'SUBMITTING...' : 'POST REVIEW'}
                            </button>
                        </form>
                    </div>

                    {/* Review List */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        {reviews.length === 0 ? (
                            <div className="glass" style={{ padding: '3rem', textAlign: 'center', borderRadius: '16px', color: 'var(--text-secondary)' }}>
                                No reviews yet. Be the first to review this product!
                            </div>
                        ) : (
                            reviews.map(review => (
                                <div key={review.id} className="glass" style={{ padding: '1.5rem', borderRadius: '12px' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                        <h4 style={{ color: '#fff' }}>{review.user_name}</h4>
                                        <div style={{ color: '#fbbf24' }}>{'Γÿà'.repeat(review.rating)}{'Γÿå'.repeat(5 - review.rating)}</div>
                                    </div>
                                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.95rem', lineHeight: '1.6' }}>{review.comment}</p>
                                    <span style={{ fontSize: '0.75rem', opacity: 0.5, marginTop: '0.5rem', display: 'block' }}>
                                        {new Date(review.created_at).toLocaleDateString()}
                                    </span>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ProductDetails;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useToast } from '../context/ToastContext';
import { useCurrency } from '../context/CurrencyContext';

const Profile = () => {
    const { formatPrice } = useCurrency();
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [user, setUser] = useState(null);
    const [activeTab, setActiveTab] = useState('profile');
    const [orders, setOrders] = useState([]);
    const [loadingOrders, setLoadingOrders] = useState(false);
    const [userReviews, setUserReviews] = useState([]);
    const [loadingReviews, setLoadingReviews] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    const [profileData, setProfileData] = useState({
        firstName: '',
        lastName: '',
        phone: '',
        email: ''
    });

    const [address, setAddress] = useState({
        street: '',
        city: '',
        state: '',
        zip: '',
        country: 'India'
    });

    const [preferences, setPreferences] = useState({
        inApp: true,
        email: true,
        sms: false
    });

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            try {
                const userData = JSON.parse(storedUser);
                setUser(userData);
                setProfileData({
                    firstName: userData.firstName || '',
                    lastName: userData.lastName || '',
                    phone: userData.phone || '',
                    email: userData.email || ''
                });
                if (userData.address) {
                    setAddress({
                        street: userData.address.street || '',
                        city: userData.address.city || '',
                        state: userData.address.state || '',
                        zip: userData.address.zip || '',
                        country: userData.address.country || 'India'
                    });
                }
                if (userData.preferences) {
                    setPreferences(userData.preferences);
                }
            } catch (e) {
                console.error("Local user parse error", e);
                setUser(null);
            }
        } else {
            setUser(null);
        }
    }, []);

    useEffect(() => {
        if (user && activeTab === 'orders') {
            fetchUserOrders();
        }
        if (user && activeTab === 'reviews') {
            fetchUserReviews();
        }
    }, [user, activeTab]);

    const fetchUserOrders = async () => {
        setLoadingOrders(true);
        try {
            setOrders([]);
            setUser(prev => ({ ...prev, totalSpent: 0 }));
        } catch (error) {
            console.error('Error fetching user orders:', error);
        } finally {
            setLoadingOrders(false);
        }
    };

    const fetchUserReviews = async () => {
        setLoadingReviews(true);
        try {
            setUserReviews([]);
        } catch (error) {
            console.error('Error fetching user reviews:', error);
        } finally {
            setLoadingReviews(false);
        }
    };

    const handleCancelOrder = async (orderId) => {
        if (window.confirm('Are you sure you want to cancel this order?')) {
            showToast('Order Cancelled successfully. ≡ƒ¢æ (Simulated)');
        }
    };

    const handleProfileChange = (e) => {
        setProfileData({ ...profileData, [e.target.name]: e.target.value });
    };

    const handleAddressChange = (e) => {
        setAddress({ ...address, [e.target.name]: e.target.value });
    };

    const handleSaveProfile = async (e) => {
        e.preventDefault();
        try {
            const updatedUser = { ...user, ...profileData };
            localStorage.setItem('user', JSON.stringify(updatedUser));
            setUser(updatedUser);
            setIsEditing(false);
            showToast('Profile Updated Successfully! Γ£¿');
        } catch (error) {
            console.error('Profile Update Error:', error);
            showToast(`Update Failed: ${error.message}`, 'error');
        }
    };

    const handleSaveAddress = async (e) => {
        e.preventDefault();
        try {
            const updatedUser = { ...user, address };
            localStorage.setItem('user', JSON.stringify(updatedUser));
            setUser(updatedUser);
            showToast('Shipping Address Saved! ≡ƒôª');
        } catch (error) {
            console.error('Address Update Error:', error);
            showToast(`Save Failed: ${error.message}`, 'error');
        }
    };

    const handleSavePreferences = async () => {
        try {
            const updatedUser = { ...user, preferences };
            localStorage.setItem('user', JSON.stringify(updatedUser));
            setUser(updatedUser);
            showToast('Preferences Saved! ≡ƒöö');
        } catch (error) {
            console.error('Preferences Update Error:', error);
            showToast('Failed to save preferences.', 'error');
        }
    };

    const handleLogout = async () => {
        localStorage.removeItem('user');
        navigate('/login');
    };

    if (!user) {
        return (
            <div className="container" style={{ paddingTop: '150px', textAlign: 'center', minHeight: '60vh' }}>
                <div className="glass" style={{ padding: '3rem', maxWidth: '400px', margin: '0 auto', borderRadius: '16px' }}>
                    <h2 style={{ marginBottom: '1rem', color: '#fff' }}>Welcome to ElectroMart!</h2>
                    <p style={{ color: 'var(--text-secondary)', marginBottom: '2rem' }}>Welcome back! Please login to manage your profile and orders.</p>
                    <button
                        onClick={() => navigate('/login')}
                        className="btn-primary"
                        style={{ width: '100%' }}
                    >
                        Login Now
                    </button>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)', fontSize: '0.9rem' }}>
                        New to Folder Mart? <span onClick={() => navigate('/signup')} style={{ color: 'var(--neon-blue)', cursor: 'pointer' }}>Create Account</span>
                    </p>
                </div>
            </div>
        );
    }

    const renderOrders = () => (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            {loadingOrders ? (
                <p style={{ color: 'var(--text-secondary)', textAlign: 'center' }}>Loading your orders...</p>
            ) : orders.length === 0 ? (
                <div className="glass" style={{ padding: '3rem', textAlign: 'center', borderRadius: '16px' }}>
                    <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem' }}>You haven't placed any orders yet.</p>
                    <button className="btn-primary" onClick={() => navigate('/')}>START SHOPPING</button>
                </div>
            ) : (
                orders.map(order => (
                    <div key={order.id} className="glass" style={{ padding: '1.5rem', borderRadius: '12px', borderLeft: `4px solid ${order.status === 'Cancelled' ? '#ff4444' : 'var(--neon-blue)'}` }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                            <div>
                                <h4 style={{ color: '#fff' }}>Order #{order.id.slice(0, 8)}</h4>
                                <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Placed on {new Date(order.created_at).toLocaleDateString()}</p>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <span style={{
                                    padding: '4px 12px', borderRadius: '50px', fontSize: '0.75rem', fontWeight: 'bold',
                                    background: 'rgba(0, 243, 255, 0.1)', color: 'var(--neon-blue)', border: '1px solid var(--neon-blue)'
                                }}>{order.status.toUpperCase()}</span>
                                <p style={{ marginTop: '0.5rem', color: '#fff', fontWeight: 'bold' }}>Γé╣{order.totalAmount}</p>
                            </div>
                        </div>
                        <div style={{ borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '1rem', marginBottom: '1rem' }}>
                            <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>Items: {order.items.map(i => i.name).join(', ')}</p>
                        </div>
                        {order.status === 'Processing' && (
                            <button
                                onClick={() => handleCancelOrder(order.id)}
                                style={{ background: 'transparent', border: '1px solid #ff4444', color: '#ff4444', padding: '4px 12px', borderRadius: '4px', fontSize: '0.8rem', cursor: 'pointer' }}
                            >
                                CANCEL ORDER
                            </button>
                        )}
                    </div>
                ))
            )}
        </div>
    );

    return (
        <div className="container" style={{ paddingTop: '100px', minHeight: '80vh' }}>
            <h2 className="text-gradient" style={{ marginBottom: '2.5rem', borderLeft: '4px solid var(--neon-blue)', paddingLeft: '1rem', textTransform: 'uppercase', letterSpacing: '1px' }}>
                Secure Command Center
            </h2>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 3fr', gap: '2.5rem' }}>
                {/* Sidebar */}
                <div className="glass" style={{
                    padding: '2.5rem',
                    borderRadius: '20px',
                    height: 'fit-content',
                    border: '1px solid rgba(255,255,255,0.08)',
                    boxShadow: '0 20px 40px rgba(0,0,0,0.4)'
                }}>
                    <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                        <div style={{
                            width: '80px', height: '80px', background: 'var(--neon-blue)',
                            borderRadius: '50%', margin: '0 auto 1rem', display: 'flex',
                            alignItems: 'center', justifyContent: 'center', fontSize: '2rem',
                            color: '#000', fontWeight: 'bold', border: '3px solid rgba(255,255,255,0.1)'
                        }}>
                            {user.firstName ? user.firstName[0].toUpperCase() : 'U'}
                        </div>
                        <h3 style={{ color: '#fff' }}>{user.firstName} {user.lastName}</h3>
                        <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Member since 2024</p>

                        {user.totalSpent >= 5000 && (
                            <div style={{
                                marginTop: '1rem', background: 'linear-gradient(45deg, #fbbf24, #d97706)',
                                color: '#000', padding: '4px 12px', borderRadius: '50px',
                                fontSize: '0.7rem', fontWeight: 'bold', display: 'inline-block',
                                boxShadow: '0 0 15px rgba(251, 191, 36, 0.4)'
                            }}>
                                ≡ƒÅå Folder Mart GOLD
                            </div>
                        )}
                        {user.role === 'admin' && <span style={{ background: 'var(--neon-blue)', color: '#000', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem', marginTop: '0.5rem', display: 'inline-block' }}>ADMIN</span>}
                    </div>
                    <ul style={{ listStyle: 'none' }}>
                        <li
                            onClick={() => setActiveTab('profile')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'profile' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            ≡ƒæñ Profile & Security
                        </li>
                        <li
                            onClick={() => setActiveTab('address')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'address' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            ≡ƒôì Address Book
                        </li>
                        <li
                            onClick={() => setActiveTab('orders')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'orders' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            ≡ƒôª Order History
                        </li>
                        <li
                            onClick={() => setActiveTab('reviews')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'reviews' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            Γ¡É My Reviews
                        </li>
                        <li
                            onClick={() => setActiveTab('refer')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'refer' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            ≡ƒÄü Refer & Earn
                        </li>
                        <li
                            onClick={() => setActiveTab('notifications')}
                            style={{ padding: '0.5rem 0', color: activeTab === 'notifications' ? 'var(--neon-blue)' : 'var(--text-secondary)', cursor: 'pointer', transition: '0.3s' }}
                        >
                            ≡ƒöö Notifications
                        </li>
                        <li style={{ padding: '1rem 0 0 0', borderTop: '1px solid rgba(255,255,255,0.1)', marginTop: '1rem' }}>
                            <button onClick={handleLogout} style={{ background: 'transparent', border: '1px solid var(--glass-border)', color: '#ff4444', padding: '8px 16px', borderRadius: '50px', cursor: 'pointer', width: '100%' }}>Logout</button>
                        </li>
                    </ul>
                </div>

                {/* Content Area */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>
                    {activeTab === 'profile' && (
                        <div className="glass" style={{ padding: '2rem', borderRadius: '16px' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                                <h3 style={{ color: '#fff' }}>Personal Information</h3>
                                <button onClick={() => setIsEditing(!isEditing)} style={{ background: 'none', border: 'none', color: 'var(--neon-blue)', cursor: 'pointer' }}>
                                    {isEditing ? 'Cancel' : 'Edit'}
                                </button>
                            </div>
                            <form onSubmit={handleSaveProfile}>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                    <div>
                                        <label htmlFor="firstName" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>First Name</label>
                                        <input id="firstName" type="text" name="firstName" value={profileData.firstName} onChange={handleProfileChange} disabled={!isEditing} autoComplete="given-name"
                                            style={{ width: '100%', padding: '10px', background: isEditing ? 'rgba(255,255,255,0.1)' : 'transparent', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                    <div>
                                        <label htmlFor="lastName" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Last Name</label>
                                        <input id="lastName" type="text" name="lastName" value={profileData.lastName} onChange={handleProfileChange} disabled={!isEditing} autoComplete="family-name"
                                            style={{ width: '100%', padding: '10px', background: isEditing ? 'rgba(255,255,255,0.1)' : 'transparent', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                </div>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                                    <div>
                                        <label htmlFor="profilePhone" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Phone Number</label>
                                        <input id="profilePhone" name="phone" type="tel" value={profileData.phone} onChange={handleProfileChange} disabled={!isEditing} autoComplete="tel"
                                            style={{ width: '100%', padding: '10px', background: isEditing ? 'rgba(255,255,255,0.1)' : 'transparent', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                    <div>
                                        <label htmlFor="profileEmail" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Email</label>
                                        <input id="profileEmail" name="email" type="email" value={profileData.email} disabled
                                            style={{ width: '100%', padding: '10px', background: 'transparent', border: '1px solid var(--glass-border)', color: '#aaa', borderRadius: '8px' }} />
                                    </div>
                                </div>
                                {isEditing && <button className="btn-primary" type="submit">Save Changes</button>}
                            </form>
                        </div>
                    )}

                    {activeTab === 'address' && (
                        <div className="glass" style={{ padding: '2rem', borderRadius: '16px' }}>
                            <h3 style={{ marginBottom: '1.5rem', color: '#fff' }}>Delivery Address</h3>
                            <form onSubmit={handleSaveAddress}>
                                <div style={{ marginBottom: '1rem' }}>
                                    <label htmlFor="street" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Street Address</label>
                                    <input id="street" type="text" name="street" value={address.street} onChange={handleAddressChange} autoComplete="street-address" style={{ width: '100%', padding: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                </div>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                    <div>
                                        <label htmlFor="city" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>City</label>
                                        <input id="city" type="text" name="city" value={address.city} onChange={handleAddressChange} autoComplete="address-level2" style={{ width: '100%', padding: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                    <div>
                                        <label htmlFor="state" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>State</label>
                                        <input id="state" type="text" name="state" value={address.state} onChange={handleAddressChange} autoComplete="address-level1" style={{ width: '100%', padding: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                    <div>
                                        <label htmlFor="zip" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>ZIP Code</label>
                                        <input id="zip" type="text" name="zip" value={address.zip} onChange={handleAddressChange} autoComplete="postal-code" style={{ width: '100%', padding: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                    </div>
                                </div>
                                <div style={{ marginBottom: '2rem' }}>
                                    <label htmlFor="country" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Country</label>
                                    <input id="country" type="text" name="country" value={address.country} onChange={handleAddressChange} autoComplete="country-name" style={{ width: '100%', padding: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px' }} />
                                </div>
                                <button className="btn-primary" type="submit">Save Address</button>
                            </form>
                        </div>
                    )}

                    {activeTab === 'orders' && renderOrders()}

                    {activeTab === 'reviews' && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                            {loadingReviews ? (
                                <p style={{ color: 'var(--text-secondary)', textAlign: 'center' }}>Loading your reviews...</p>
                            ) : userReviews.length === 0 ? (
                                <div className="glass" style={{ padding: '3rem', textAlign: 'center', borderRadius: '16px' }}>
                                    <p style={{ color: 'var(--text-secondary)' }}>You haven't reviewed any products yet.</p>
                                </div>
                            ) : (
                                userReviews.map(review => (
                                    <div key={review.id} className="glass" style={{ padding: '1.5rem', borderRadius: '12px' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                            <h4 style={{ color: 'var(--neon-blue)' }}>{review.products?.name}</h4>
                                            <div style={{ color: '#fbbf24' }}>{'Γÿà'.repeat(review.rating)}</div>
                                        </div>
                                        <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>{review.comment}</p>
                                        <span style={{ fontSize: '0.7rem', opacity: 0.5 }}>{new Date(review.created_at).toLocaleDateString()}</span>
                                    </div>
                                ))
                            )}
                        </div>
                    )}

                    {activeTab === 'refer' && (
                        <div className="glass animate-slide-up" style={{
                            padding: '3rem',
                            borderRadius: '24px',
                            textAlign: 'center',
                            border: '1px solid rgba(0, 243, 255, 0.1)',
                            background: 'radial-gradient(circle at top right, rgba(0, 243, 255, 0.05), transparent)'
                        }}>
                            <div style={{ fontSize: '3.5rem', marginBottom: '1.5rem', filter: 'drop-shadow(0 0 10px var(--neon-blue))' }}>≡ƒÆÄ</div>
                            <h3 style={{ color: '#fff', marginBottom: '1rem', textTransform: 'uppercase', letterSpacing: '2px' }}>Network Expansion</h3>
                            <p style={{ color: 'var(--text-secondary)', marginBottom: '2.5rem', maxWidth: '400px', margin: '0 auto 2.5rem' }}>
                                Recruit fellow creators to the Folder Mart ecosystem. You receive <strong>{formatPrice(100)}</strong> credits for every successful authorization.
                            </p>

                            <div style={{
                                background: 'rgba(0, 0, 0, 0.4)',
                                border: '1px solid var(--neon-blue)',
                                padding: '1.2rem',
                                borderRadius: '12px',
                                position: 'relative',
                                marginBottom: '1.5rem',
                                boxShadow: 'inset 0 0 20px rgba(0, 243, 255, 0.1)'
                            }}>
                                <span style={{
                                    fontFamily: 'monospace',
                                    fontSize: '1.4rem',
                                    color: 'var(--neon-blue)',
                                    letterSpacing: '3px',
                                    fontWeight: 'bold'
                                }}>
                                    FM-{user.firstName?.toUpperCase() || 'USER'}-2024
                                </span>
                                <button
                                    onClick={() => {
                                        navigator.clipboard.writeText(`FM-${user.firstName?.toUpperCase() || 'USER'}-2024`);
                                        showToast('Referral Protocol Copied! ≡ƒôí');
                                    }}
                                    style={{
                                        position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)',
                                        background: 'var(--neon-blue)', color: '#000', border: 'none',
                                        borderRadius: '6px', padding: '6px 15px', fontSize: '0.75rem',
                                        fontWeight: 'bold', cursor: 'pointer', transition: '0.2s'
                                    }}
                                    onMouseOver={(e) => e.target.style.transform = 'translateY(-50%) scale(1.05)'}
                                    onMouseOut={(e) => e.target.style.transform = 'translateY(-50%) scale(1)'}
                                >COPY ID</button>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'center', gap: '2rem', marginTop: '2rem' }}>
                                <div>
                                    <p style={{ fontSize: '0.7rem', color: '#888', textTransform: 'uppercase' }}>Credits Earned</p>
                                    <p style={{ fontSize: '1.2rem', color: '#fff', fontWeight: 'bold' }}>{formatPrice(0)}</p>
                                </div>
                                <div style={{ borderLeft: '1px solid rgba(255,255,255,0.1)' }}></div>
                                <div>
                                    <p style={{ fontSize: '0.7rem', color: '#888', textTransform: 'uppercase' }}>Active Referrals</p>
                                    <p style={{ fontSize: '1.2rem', color: '#fff', fontWeight: 'bold' }}>0</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {activeTab === 'notifications' && (
                        <div className="glass" style={{ padding: '2rem', borderRadius: '16px' }}>
                            <h3 style={{ marginBottom: '1.5rem', color: '#fff' }}>Notification Preferences</h3>
                            <p style={{ color: 'var(--text-secondary)', marginBottom: '2rem', fontSize: '0.9rem' }}>Choose how you want to receive updates about your orders and favorite products.</p>

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '1rem', borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                    <div>
                                        <h4 style={{ color: '#fff' }}>In-App Notifications</h4>
                                        <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Get alerts inside the application for order status and price drops.</p>
                                    </div>
                                    <input
                                        id="pref-in-app"
                                        name="pref_in_app"
                                        type="checkbox"
                                        checked={preferences.inApp}
                                        onChange={(e) => setPreferences({ ...preferences, inApp: e.target.checked })}
                                        style={{ width: '20px', height: '20px', cursor: 'pointer', accentColor: 'var(--neon-blue)' }}
                                    />
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <div>
                                        <h4 style={{ color: '#fff' }}>SMS Alerts</h4>
                                        <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Get critical shipping updates and flash sale alerts on your phone.</p>
                                    </div>
                                    <input
                                        id="pref-sms"
                                        name="pref_sms"
                                        type="checkbox"
                                        checked={preferences.sms}
                                        onChange={(e) => setPreferences({ ...preferences, sms: e.target.checked })}
                                        style={{ width: '20px', height: '20px', cursor: 'pointer', accentColor: 'var(--neon-blue)' }}
                                    />
                                </div>
                            </div>

                            <button className="btn-primary" onClick={handleSavePreferences} style={{ marginTop: '2.5rem', width: '100%' }}>SAVE PREFERENCES</button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Profile;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useToast } from '../context/ToastContext';

const Signup = () => {
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        confirmPassword: ''
    });

    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (formData.password.length < 6) {
            showToast("Security Violation: Password must be at least 6 tokens.", "error");
            return;
        }

        if (formData.password !== formData.confirmPassword) {
            showToast("Identity Mismatch: Passwords do not correlate.", "error");
            return;
        }

        setLoading(true);
        try {
            // Admin Emails
            const adminEmails = ['ishanisharma77289@gmail.com', 'ugantsharma@89', 'bipiye3181@ixospace.com'];
            const isAdmin = adminEmails.includes(formData.email.toLowerCase().trim());

            // Simulated signup logic without firebase
            await new Promise(resolve => setTimeout(resolve, 800));

            showToast('Registration Successful! ≡ƒÄë Welcome. (Firebase Disabled)');
            navigate('/login');
        } catch (error) {
            console.error('Signup Error:', error);
            showToast(error.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container" style={{
            paddingTop: '0',
            minHeight: '100vh',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            alignItems: 'center',
            position: 'relative',
            overflow: 'hidden'
        }}>
            <Link to="/" style={{
                position: 'absolute', top: '120px', left: '2rem',
                color: 'var(--text-secondary)', zIndex: 10, textDecoration: 'none',
                display: 'flex', alignItems: 'center', gap: '8px'
            }}>
                ΓåÉ BACK TO STORE
            </Link>

            {/* Animated Background Elements */}
            <div className="login-bg-glow animate-float" style={{ top: '10%', left: '5%' }}></div>
            <div className="login-bg-glow animate-float" style={{ bottom: '5%', right: '5%', background: 'radial-gradient(circle, rgba(112, 0, 255, 0.1) 0%, rgba(0, 0, 0, 0) 70%)', animationDelay: '2s' }}></div>

            <div className="glass animate-slide-up" style={{
                padding: '3rem',
                borderRadius: '24px',
                width: '100%',
                maxWidth: '450px',
                position: 'relative',
                zIndex: 1,
                border: '1px solid rgba(255,255,255,0.08)',
                backdropFilter: 'blur(30px)'
            }}>
                <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                    <h2 style={{ color: '#fff', letterSpacing: '2px', fontFamily: 'var(--font-mono)' }}>CREATE SYSTEM IDENTITY</h2>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Join the Folder Mart network</p>
                </div>

                <form onSubmit={handleSubmit}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                        <div>
                            <label htmlFor="firstName" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>First Name</label>
                            <input
                                id="signup-firstName"
                                name="firstName"
                                type="text"
                                required
                                autoComplete="given-name"
                                value={formData.firstName}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px', outline: 'none' }}
                            />
                        </div>
                        <div>
                            <label htmlFor="lastName" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Last Name</label>
                            <input
                                id="signup-lastName"
                                name="lastName"
                                type="text"
                                required
                                autoComplete="family-name"
                                value={formData.lastName}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px', outline: 'none' }}
                            />
                        </div>
                    </div>

                    <div style={{ marginBottom: '1.5rem' }}>
                        <label htmlFor="email" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Email</label>
                        <input
                            id="signup-email"
                            name="email"
                            type="email"
                            required
                            autoComplete="email"
                            value={formData.email}
                            onChange={handleChange}
                            style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px', outline: 'none' }}
                        />
                    </div>

                    <div style={{ marginBottom: '1.5rem' }}>
                        <label htmlFor="password" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Password</label>
                        <div style={{ position: 'relative' }}>
                            <input
                                id="signup-password"
                                name="password"
                                type={showPassword ? "text" : "password"}
                                required
                                autoComplete="new-password"
                                value={formData.password}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '12px 45px 12px 12px', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '8px', outline: 'none' }}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                style={{
                                    position: 'absolute',
                                    right: '12px',
                                    top: '50%',
                                    transform: 'translateY(-50%)',
                                    background: 'none',
                                    border: 'none',
                                    color: 'var(--text-secondary)',
                                    cursor: 'pointer',
                                    padding: '0',
                                    display: 'flex',
                                    alignItems: 'center'
                                }}
                            >
                                {showPassword ? (
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"></path><line x1="1" y1="1" x2="23" y2="23"></line></svg>
                                ) : (
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
                                )}
                            </button>
                        </div>
                    </div>

                    <div style={{ marginBottom: '2.5rem' }}>
                        <label htmlFor="confirmPassword" style={{ display: 'block', marginBottom: '0.8rem', color: '#fff', fontSize: '0.9rem', fontWeight: '500' }}>Confirm System Key</label>
                        <div style={{ position: 'relative' }}>
                            <input
                                id="signup-confirmPassword"
                                name="confirmPassword"
                                type={showConfirmPassword ? "text" : "password"}
                                required
                                autoComplete="new-password"
                                value={formData.confirmPassword}
                                onChange={handleChange}
                                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                style={{ width: '100%', padding: '14px 45px 14px 16px', background: 'rgba(0, 0, 0, 0.3)', border: '1px solid var(--glass-border)', color: '#fff', borderRadius: '12px', outline: 'none', transition: 'all 0.3s ease', fontSize: '1rem' }}
                            />
                            <button
                                type="button"
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                style={{
                                    position: 'absolute',
                                    right: '12px',
                                    top: '50%',
                                    transform: 'translateY(-50%)',
                                    background: 'none',
                                    border: 'none',
                                    color: 'var(--text-secondary)',
                                    cursor: 'pointer',
                                    padding: '0',
                                    display: 'flex',
                                    alignItems: 'center'
                                }}
                            >
                                {showConfirmPassword ? (
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"></path><line x1="1" y1="1" x2="23" y2="23"></line></svg>
                                ) : (
                                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
                                )}
                            </button>
                        </div>
                    </div>

                    <button className="btn-primary" type="submit" style={{ width: '100%', padding: '14px', fontSize: '1.1rem' }} disabled={loading}>
                        {loading ? 'INITIALIZING...' : 'AUTHORIZE ACCOUNT'}
                    </button>


                    <p style={{ marginTop: '1.5rem', textAlign: 'center', color: 'var(--text-secondary)' }}>
                        Already have an account? <Link to="/login" style={{ color: 'var(--neon-blue)', cursor: 'pointer', textDecoration: 'none' }}>Login</Link>
                    </p>
                </form>
            </div>
        </div>
    );
};

export default Signup;
